/**
 * CSV Parser Library (JavaScript)
 * Comprehensive CSV parsing with support for quoted fields, 
 * custom delimiters, type coercion, and data aggregation.
 */

// ============================================================================
// CSV Result Class
// ============================================================================

class CSVResult {
  constructor(rows, headers, errors = []) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows using a predicate function
   */
  filter(predicate) {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum all numeric values in a column
   */
  sum(column) {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : parseFloat(value);
      return isNaN(num) ? acc : acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column) {
    const validValues = this.rows
      .map((row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : parseFloat(value);
        return isNaN(num) ? null : num;
      })
      .filter((v) => v !== null);

    if (validValues.length === 0) return 0;
    const sum = validValues.reduce((acc, v) => acc + v, 0);
    return sum / validValues.length;
  }

  /**
   * Count total number of rows
   */
  count() {
    return this.rows.length;
  }

  /**
   * Group rows by column values
   */
  groupBy(column) {
    return this.rows.reduce((acc, row) => {
      const key = String(row[column] ?? 'null');
      if (!acc[key]) {
        acc[key] = [];
      }
      acc[key].push(row);
      return acc;
    }, {});
  }
}

// ============================================================================
// Type Coercion
// ============================================================================

function coerceValue(value) {
  // Handle null values
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  // Handle booleans (case-insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers (both integers and floats)
  if (/^-?\d+(\.\d+)?$/.test(value.trim())) {
    const num = parseFloat(value);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Everything else stays as string
  return value;
}

// ============================================================================
// CSV Parser
// ============================================================================

function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  // Handle empty input
  if (!input || input.trim().length === 0) {
    return new CSVResult([], [], []);
  }

  // Split into lines
  const lines = input.split(lineSeparator);
  const errors = [];
  const parsedRows = [];

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse header row
  let headers = [];
  try {
    headers = parseRow(lines[0], delimiter, quoteChar);
  } catch (error) {
    errors.push({
      row: 1,
      message: `Failed to parse header row: ${error.message}`,
    });
    return new CSVResult([], [], errors);
  }

  // Parse data rows
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim().length === 0) {
      continue;
    }

    try {
      const fields = parseRow(line, delimiter, quoteChar);

      // Validate row length
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Row has ${fields.length} fields but expected ${headers.length}`,
        });
        continue;
      }

      // Build row object with type coercion
      const row = {};
      for (let j = 0; j < headers.length; j++) {
        row[headers[j]] = coerceValue(fields[j]);
      }

      parsedRows.push(row);
    } catch (error) {
      errors.push({
        row: i + 1,
        message: `Failed to parse row: ${error.message}`,
      });
    }
  }

  return new CSVResult(parsedRows, headers, errors);
}

// ============================================================================
// Row Parser
// ============================================================================

/**
 * Parse a single CSV row, handling quoted fields and escaped quotes
 */
function parseRow(line, delimiter, quoteChar) {
  const fields = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = i + 1 < line.length ? line[i + 1] : '';

    // Handle quote character
    if (char === quoteChar) {
      if (inQuotes && nextChar === quoteChar) {
        // Escaped quote (two quotes = one literal)
        current += quoteChar;
        i += 2;
        continue;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
        continue;
      }
    }

    // Handle delimiter
    if (char === delimiter && !inQuotes) {
      fields.push(current);
      current = '';
      i++;
      continue;
    }

    // Regular character
    current += char;
    i++;
  }

  // Add last field
  fields.push(current);

  // Validate quote state
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

// ============================================================================
// Export
// ============================================================================

module.exports = { parseCSV, CSVResult };

/**
 * CSV Parser Test Suite (JavaScript)
 * Comprehensive tests covering all functionality and edge cases
 */

const { parseCSV, CSVResult } = require('./csv-parser.js');

// ============================================================================
// Test Utilities
// ============================================================================

let testCount = 0;
let passCount = 0;
let failCount = 0;

function assert(condition, message) {
  testCount++;
  if (condition) {
    passCount++;
    console.log(`вњ“ ${message}`);
  } else {
    failCount++;
    console.error(`вњ— ${message}`);
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual(actual, expected, message) {
  assert(
    JSON.stringify(actual) === JSON.stringify(expected),
    `${message} (expected: ${JSON.stringify(expected)}, got: ${JSON.stringify(actual)})`
  );
}

function assertApprox(actual, expected, tolerance, message) {
  assert(
    Math.abs(actual - expected) <= tolerance,
    `${message} (expected ~${expected}, got ${actual})`
  );
}

function testSection(name) {
  console.log(`\n${'='.repeat(60)}`);
  console.log(`TEST SECTION: ${name}`);
  console.log(`${'='.repeat(60)}`);
}

function testSummary() {
  console.log(`\n${'='.repeat(60)}`);
  console.log(`TEST SUMMARY`);
  console.log(`${'='.repeat(60)}`);
  console.log(`Total: ${testCount} | Passed: ${passCount} | Failed: ${failCount}`);
  if (failCount === 0) {
    console.log('вњ“ All tests passed!');
  } else {
    console.log(`вњ— ${failCount} test(s) failed`);
    process.exit(1);
  }
}

// ============================================================================
// BASIC PARSING TESTS
// ============================================================================

testSection('Basic Parsing');

const basicCSV = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,Chicago`;

const basicResult = parseCSV(basicCSV);
assertEqual(basicResult.headers, ['name', 'age', 'city'], 'Headers parsed correctly');
assertEqual(basicResult.rows.length, 3, 'Correct number of rows');
assertEqual(basicResult.rows[0], { name: 'John', age: 30, city: 'New York' }, 'First row parsed correctly');
assertEqual(basicResult.rows[1], { name: 'Jane', age: 25, city: 'Los Angeles' }, 'Second row parsed correctly');
assertEqual(basicResult.rows[2], { name: 'Bob', age: 35, city: 'Chicago' }, 'Third row parsed correctly');
assertEqual(basicResult.errors.length, 0, 'No errors in basic parsing');

// Test single row
const singleRowCSV = `id,value
1,test`;
const singleResult = parseCSV(singleRowCSV);
assertEqual(singleResult.rows.length, 1, 'Single row parsed');
assertEqual(singleResult.rows[0].id, 1, 'Single row data correct');

// Test single column
const singleColCSV = `name
Alice
Bob`;
const singleColResult = parseCSV(singleColCSV);
assertEqual(singleColResult.headers, ['name'], 'Single column header');
assertEqual(singleColResult.rows.length, 2, 'Single column rows');
assertEqual(singleColResult.rows[0].name, 'Alice', 'Single column data');

// ============================================================================
// QUOTED FIELDS TESTS
// ============================================================================

testSection('Quoted Fields');

const quotedCSV = `name,description,value
"Smith, John","A person with, comma in name",100
"Jane ""The Boss"" Doe","Contains ""quotes""",200`;

const quotedResult = parseCSV(quotedCSV);
assertEqual(quotedResult.rows[0].name, 'Smith, John', 'Quoted field with comma handled');
assertEqual(quotedResult.rows[0].description, 'A person with, comma in name', 'Quoted field with comma preserved');
assertEqual(quotedResult.rows[1].name, 'Jane "The Boss" Doe', 'Escaped quotes handled');
assertEqual(quotedResult.rows[1].description, 'Contains "quotes"', 'Quotes unescaped correctly');

// Mixed quoted and unquoted
const mixedQuotesCSV = `id,name,value
1,John,simple
2,"Complex, Name",quoted`;
const mixedResult = parseCSV(mixedQuotesCSV);
assertEqual(mixedResult.rows[0].name, 'John', 'Unquoted field');
assertEqual(mixedResult.rows[1].name, 'Complex, Name', 'Quoted field with comma');

// Quoted field with newlines (within same line)
const quotedNewlineCSV = `title,body
"Multi-word Title","Content here"`;
const quotedNewlineResult = parseCSV(quotedNewlineCSV);
assertEqual(quotedNewlineResult.rows[0].title, 'Multi-word Title', 'Quoted field');

// ============================================================================
// ESCAPED QUOTES TESTS
// ============================================================================

testSection('Escaped Quotes');

const escapedQuotesCSV = `text
"""quoted at start"
"end with quote"""
"middle "" quote"
""""double quotes""""`;

const escapedResult = parseCSV(escapedQuotesCSV);
assertEqual(escapedResult.rows[0].text, '"quoted at start', 'Quote at start');
assertEqual(escapedResult.rows[1].text, 'end with quote"', 'Quote at end');
assertEqual(escapedResult.rows[2].text, 'middle " quote', 'Middle quote');
assertEqual(escapedResult.rows[3].text, '""double quotes""', 'Double escaped quotes');

// ============================================================================
// CUSTOM DELIMITERS TESTS
// ============================================================================

testSection('Custom Delimiters');

const semicolonCSV = `name;age;city
John;30;New York
Jane;25;Los Angeles`;

const semicolonResult = parseCSV(semicolonCSV, { delimiter: ';' });
assertEqual(semicolonResult.headers, ['name', 'age', 'city'], 'Semicolon delimiter headers');
assertEqual(semicolonResult.rows[0].name, 'John', 'Semicolon delimiter row');

// Tab delimiter
const tabCSV = `name\tage\tcity
John\t30\tNew York`;

const tabResult = parseCSV(tabCSV, { delimiter: '\t' });
assertEqual(tabResult.headers, ['name', 'age', 'city'], 'Tab delimiter headers');
assertEqual(tabResult.rows[0].age, 30, 'Tab delimiter data');

// Pipe delimiter
const pipeCSV = `id|name|value
1|Alice|100
2|Bob|200`;

const pipeResult = parseCSV(pipeCSV, { delimiter: '|' });
assertEqual(pipeResult.rows.length, 2, 'Pipe delimiter rows');
assertEqual(pipeResult.rows[0].name, 'Alice', 'Pipe delimiter data');

// Custom quote character
const betterCustomQuoteCSV = `name,description
{Smith, John},{A person with, comma}`;

const betterCustomQuoteResult = parseCSV(betterCustomQuoteCSV, { quoteChar: '{' });
assertEqual(betterCustomQuoteResult.rows[0].name, 'Smith, John', 'Custom quote character');
assertEqual(betterCustomQuoteResult.rows[0].description, 'A person with, comma', 'Custom quote description');

// ============================================================================
// TYPE COERCION TESTS
// ============================================================================

testSection('Type Coercion');

const typeCoercionCSV = `id,count,price,active,status,empty_field,nullable
1,100,19.99,true,True,,null
2,0,0.5,false,FALSE,,NULL
3,999,3.14159,yes,yes,`;

const typeResult = parseCSV(typeCoercionCSV);

// Integers
assertEqual(typeResult.rows[0].id, 1, 'Integer coerced');
assert(typeof typeResult.rows[0].id === 'number', 'Integer is number type');

// Floats
assertEqual(typeResult.rows[0].price, 19.99, 'Float coerced');
assert(typeof typeResult.rows[0].price === 'number', 'Float is number type');

// Booleans (true)
assertEqual(typeResult.rows[0].active, true, 'true coerced to boolean');
assert(typeof typeResult.rows[0].active === 'boolean', 'true is boolean type');

// Booleans (false)
assertEqual(typeResult.rows[1].active, false, 'false coerced to boolean');
assert(typeof typeResult.rows[1].active === 'boolean', 'false is boolean type');

// Booleans (case-insensitive)
assertEqual(typeResult.rows[0].status, true, 'True (uppercase) coerced');
assertEqual(typeResult.rows[1].status, false, 'FALSE (uppercase) coerced');

// Null values (empty string)
assertEqual(typeResult.rows[0].empty_field, null, 'Empty string coerced to null');

// Null values (explicit null)
assertEqual(typeResult.rows[0].nullable, null, 'null string coerced to null');
assertEqual(typeResult.rows[1].nullable, null, 'NULL (uppercase) coerced to null');

// String stays string
const stringCoercionCSV = `name,value
Alice,hello
Bob,12abc`;

const stringResult = parseCSV(stringCoercionCSV);
assertEqual(stringResult.rows[0].name, 'Alice', 'String stays string');
assertEqual(stringResult.rows[1].value, '12abc', 'Partial number stays string');

// Negative numbers
const negativeCSV = `value
-42
-3.14`;

const negativeResult = parseCSV(negativeCSV);
assertEqual(negativeResult.rows[0].value, -42, 'Negative integer');
assertEqual(negativeResult.rows[1].value, -3.14, 'Negative float');

// ============================================================================
// ERROR HANDLING TESTS
// ============================================================================

testSection('Error Handling');

// Malformed row - wrong number of fields
const malformedCSV = `name,age,city
John,30,New York
Jane,25
Bob,35,Chicago,extra_field`;

const malformedResult = parseCSV(malformedCSV);
assertEqual(malformedResult.errors.length, 2, 'Errors collected for malformed rows');
assertEqual(malformedResult.rows.length, 1, 'Valid row still parsed');
assertEqual(malformedResult.rows[0].name, 'John', 'First valid row parsed');
assert(malformedResult.errors[0].row === 3, 'Error row number correct (Jane)');
assert(malformedResult.errors[1].row === 5, 'Error row number correct (extra field)');

// Unclosed quotes
const unclosedQuoteCSV = `name,value
"John Doe,100`;

const unclosedResult = parseCSV(unclosedQuoteCSV);
assertEqual(unclosedResult.errors.length, 1, 'Unclosed quote error collected');
assert(unclosedResult.errors[0].message.includes('Unclosed'), 'Error message mentions unclosed');

// Empty input
const emptyResult = parseCSV('');
assertEqual(emptyResult.rows.length, 0, 'Empty input handled');
assertEqual(emptyResult.headers.length, 0, 'Empty input no headers');

// Whitespace only
const whitespaceResult = parseCSV('   \n  \n  ');
assertEqual(whitespaceResult.rows.length, 0, 'Whitespace only handled');

// Header only
const headerOnlyCSV = `id,name,value`;
const headerOnlyResult = parseCSV(headerOnlyCSV);
assertEqual(headerOnlyResult.headers, ['id', 'name', 'value'], 'Header only parsed');
assertEqual(headerOnlyResult.rows.length, 0, 'No data rows from header only');

// ============================================================================
// FILTER TESTS
// ============================================================================

testSection('Filtering');

const filterCSV = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,Chicago
Alice,28,New York`;

const filterData = parseCSV(filterCSV);

// Filter by age
const ageFilterResult = filterData.filter((row) => row.age >= 30);
assertEqual(ageFilterResult.rows.length, 2, 'Filter by age >= 30');
assertEqual(ageFilterResult.rows[0].name, 'John', 'First filtered row');
assertEqual(ageFilterResult.rows[1].name, 'Bob', 'Second filtered row');

// Filter by city
const cityFilterResult = filterData.filter((row) => row.city === 'New York');
assertEqual(cityFilterResult.rows.length, 2, 'Filter by city');
assertEqual(cityFilterResult.rows[0].name, 'John', 'City filter result 1');
assertEqual(cityFilterResult.rows[1].name, 'Alice', 'City filter result 2');

// Filter with predicate index
const indexFilterResult = filterData.filter((row, index) => index % 2 === 0);
assertEqual(indexFilterResult.rows.length, 2, 'Filter by index');
assertEqual(indexFilterResult.rows[0].name, 'John', 'Index filter result 1');

// Chain filters
const chainedFilterResult = filterData
  .filter((row) => row.age >= 25)
  .filter((row) => row.city === 'New York');
assertEqual(chainedFilterResult.rows.length, 2, 'Chained filters');

// Filter all
const filterAllResult = filterData.filter(() => true);
assertEqual(filterAllResult.rows.length, 4, 'Filter all');

// Filter none
const filterNoneResult = filterData.filter(() => false);
assertEqual(filterNoneResult.rows.length, 0, 'Filter none');

// ============================================================================
// AGGREGATION - SUM TESTS
// ============================================================================

testSection('Aggregation - Sum');

const sumCSV = `product,quantity,price
Apple,5,1.50
Banana,3,0.75
Orange,8,2.00
Grape,10,0.50`;

const sumData = parseCSV(sumCSV);

const quantitySum = sumData.sum('quantity');
assertEqual(quantitySum, 26, 'Sum of quantities');

const priceSum = sumData.sum('price');
assertApprox(priceSum, 4.75, 0.01, 'Sum of prices');

// Sum on filtered data
const largeOrderSum = sumData
  .filter((row) => row.quantity > 5)
  .sum('quantity');
assertEqual(largeOrderSum, 18, 'Sum on filtered data');

// Sum with non-numeric values
const mixedSumCSV = `id,value
1,100
2,abc
3,50`;

const mixedSumData = parseCSV(mixedSumCSV);
const mixedSum = mixedSumData.sum('value');
assertEqual(mixedSum, 150, 'Sum skips non-numeric');

// ============================================================================
// AGGREGATION - AVERAGE TESTS
// ============================================================================

testSection('Aggregation - Average');

const averageCSV = `student,score
Alice,90
Bob,85
Charlie,95
Diana,80`;

const averageData = parseCSV(averageCSV);
const scoreAverage = averageData.average('score');
assertEqual(scoreAverage, 87.5, 'Average of scores');

// Average with empty values
const avgWithNullCSV = `score

90
85

95`;

const avgWithNullData = parseCSV(avgWithNullCSV);
const avgIgnoresNull = avgWithNullData.average('score');
assertEqual(avgIgnoresNull, 90, 'Average ignores null values');

// Average on filtered data
const highScoreAvg = averageData
  .filter((row) => row.score > 85)
  .average('score');
assertEqual(highScoreAvg, 92.5, 'Average on filtered data');

// Average of single value
const singleAvgCSV = `value
42`;

const singleAvgData = parseCSV(singleAvgCSV);
const singleAvg = singleAvgData.average('value');
assertEqual(singleAvg, 42, 'Average of single value');

// ============================================================================
// AGGREGATION - COUNT TESTS
// ============================================================================

testSection('Aggregation - Count');

const countData = parseCSV(filterCSV);
