const filteredCountData = countData.filter((row) => row.age >= 30);
assertEqual(filteredCountData.count(), 2, 'Count filtered rows');

const emptyCountData = countData.filter(() => false);
assertEqual(emptyCountData.count(), 0, 'Count empty result');

// ============================================================================
// AGGREGATION - GROUP BY TESTS
// ============================================================================

testSection('Aggregation - GroupBy');

const groupByCSV = `department,employee,salary
Sales,John,50000
Sales,Jane,55000
Engineering,Bob,80000
Engineering,Alice,85000
HR,Charlie,60000`;

const groupByData = parseCSV(groupByCSV);
const grouped = groupByData.groupBy('department');

assert('Sales' in grouped, 'Sales group exists');
assert('Engineering' in grouped, 'Engineering group exists');
assert('HR' in grouped, 'HR group exists');

