assertEqual(grouped['Engineering'].length, 2, 'Engineering group has 2 people');
assertEqual(grouped['HR'].length, 1, 'HR group has 1 person');

assertEqual(grouped['Sales'][0].employee, 'John', 'First sales employee');
assertEqual(grouped['Engineering'][0].salary, 80000, 'Bob salary');

// Group by number
const groupByNumData = parseCSV(sumCSV);
