assertEqual(floatEdgeCaseResult.rows[0].value, '.5', 'Decimal without leading 0 stays string');
assertEqual(floatEdgeCaseResult.rows[1].value, '5.', 'Decimal without trailing digit stays string');
assertEqual(floatEdgeCaseResult.rows[2].value, 0, 'Zero point zero is number');

// ============================================================================
// INTEGRATION TESTS
// ============================================================================

testSection('Integration Tests');

// Complex real-world scenario
const complexCSV = `id,name,department,salary,active,notes
1,"Smith, John",Sales,50000,true,"Great ""performer"""
2,Jane Doe,Engineering,85000,true,
3,"Johnson, Bob",Sales,52000,false,"Needs review, evaluation pending"
4,Alice Brown,Engineering,90000,true,"Lead engineer, multi-talented"
5,,HR,60000,,`;

const complexResult = parseCSV(complexCSV);
assertEqual(complexResult.rows.length, 4, 'Complex CSV main rows');
assertEqual(complexResult.errors.length, 1, 'Complex CSV has 1 error (incomplete row)');

// Chain operations
const chainedResult = complexResult
  .filter((row) => row.active === true)
  .filter((row) => row.department === 'Engineering')
  .groupBy('department');

assertEqual(chainedResult['Engineering'].length, 2, 'Chained operations work');

// Sum and average on filtered data
const salaryStats = complexResult
  .filter((row) => row.department === 'Sales')
  .sum('salary');

assertEqual(salaryStats, 102000, 'Sum on specific department');

const engAvg = complexResult
  .filter((row) => row.department === 'Engineering')
  .average('salary');

assertEqual(engAvg, 87500, 'Average on specific department');

