## Error Handling

### Detecting Errors

```typescript
const csv = `name,age,city
John,30,New York
Jane,25
Bob,35,Chicago,Extra`;

const result = parseCSV(csv);

console.log(result.rows.length);  // 1 (only John)
console.log(result.errors.length); // 2

result.errors.forEach(error => {
  console.log(`Row ${error.row}: ${error.message}`);
});
// Row 3: Row has 2 fields but expected 3
// Row 5: Row has 4 fields but expected 3
```

### Validating Data

```typescript
const result = parseCSV(csv);

if (result.errors.length > 0) {
  console.log(`CSV has ${result.errors.length} parsing errors`);
  console.log('Errors:');
  result.errors.forEach(error => {
    console.log(`  - ${error.message} (row ${error.row})`);
  });
}

// Process only valid rows
result.rows.forEach(row => {
  // This row has correct number of fields
  console.log(`Processing: ${row.name}`);
});
```

### Handling Malformed Data

```typescript
const csv = `name,score,status
Alice,95,Pass
Bob,87,Pass
Charlie,45
Diana,92,Pass`;

const result = parseCSV(csv);

// Process valid rows
