## Aggregation

### Sum Operations

```typescript
const csv = `product,quantity,unit_price
Apple,5,1.50
Banana,3,0.75
Orange,8,2.00
Grape,10,0.50`;

const result = parseCSV(csv);

// Total quantity
const totalQty = result.sum('quantity');
console.log(`Total items: ${totalQty}`); // 26

// Total revenue
const totalRevenue = result.rows.reduce((sum, row) => 
  sum + (row.quantity * row.unit_price), 0
);
console.log(`Total revenue: $${totalRevenue.toFixed(2)}`);

// Sum of large orders only
const largeOrderQty = result
  .filter(row => row.quantity > 5)
  .sum('quantity');
console.log(`Large orders: ${largeOrderQty}`); // 18
```

### Average Operations

```typescript
const csv = `student,exam1,exam2,exam3
Alice,90,85,92
Bob,78,82,88
Charlie,95,91,89
Diana,88,90,86`;

const result = parseCSV(csv);

// Average of first exam
const avg1 = result.average('exam1');
console.log(`Exam 1 average: ${avg1.toFixed(2)}`);

// Average of top performers
const topAvg = result
  .filter(row => 
    (row.exam1 + row.exam2 + row.exam3) / 3 > 85
  )
  .average('exam1');
console.log(`Top performers exam 1 avg: ${topAvg.toFixed(2)}`);
```

### Count Operations

```typescript
// Total rows
const total = result.count();
console.log(`Total students: ${total}`);

// Filtered count
