## Error Handling Best Practices

```typescript
const parseCSVsafely = (csv, options = {}) => {
  try {
    const result = parseCSV(csv, options);

    // Check for parsing errors
    if (result.errors.length > 0) {
      console.warn(`CSV parsing had ${result.errors.length} errors:`);
      result.errors.forEach(err => {
        console.warn(`  Row ${err.row}: ${err.message}`);
      });
    }

    // Check for no data
    if (result.rows.length === 0) {
      console.warn('CSV parsing resulted in no data rows');
      return null;
    }

    return result;
  } catch (error) {
    console.error('Fatal error parsing CSV:', error);
    return null;
  }
};

const result = parseCSVsafely(csvContent);
if (result) {
  // Process data
  console.log(`Processed ${result.rows.length} rows`);
}
```

