/**
 * CSV Parser Library
 * Comprehensive TypeScript CSV parsing with support for quoted fields, 
 * custom delimiters, type coercion, and data aggregation.
 */

// ============================================================================
// Type Definitions
// ============================================================================

export interface CSVOptions {
  /** Delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character (default: '"') */
  quoteChar?: string;
  /** Line separator (default: '\n') */
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface GroupByResult {
  [key: string]: Array<Record<string, any>>;
}

export type FilterPredicate = (row: Record<string, any>, index: number) => boolean;

// ============================================================================
// CSV Result Class
// ============================================================================

export class CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];

  constructor(
    rows: Array<Record<string, any>>,
    headers: string[],
    errors: CSVError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows using a predicate function
   */
  filter(predicate: FilterPredicate): CSVResult {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum all numeric values in a column
   */
  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : parseFloat(value);
      return isNaN(num) ? acc : acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    const validValues = this.rows
      .map((row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : parseFloat(value);
        return isNaN(num) ? null : num;
      })
      .filter((v) => v !== null) as number[];

    if (validValues.length === 0) return 0;
    const sum = validValues.reduce((acc, v) => acc + v, 0);
    return sum / validValues.length;
  }

  /**
   * Count total number of rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by column values
   */
  groupBy(column: string): GroupByResult {
    return this.rows.reduce((acc: GroupByResult, row) => {
      const key = String(row[column] ?? 'null');
      if (!acc[key]) {
        acc[key] = [];
      }
      acc[key].push(row);
      return acc;
    }, {});
  }
}

// ============================================================================
// Type Coercion
// ============================================================================

function coerceValue(value: string): any {
  // Handle null values
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  // Handle booleans (case-insensitive)
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers (both integers and floats)
  if (/^-?\d+(\.\d+)?$/.test(value.trim())) {
    const num = parseFloat(value);
    if (!isNaN(num)) {
      return num;
    }
  }

  // Everything else stays as string
  return value;
}

// ============================================================================
// CSV Parser
// ============================================================================

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  // Handle empty input
  if (!input || input.trim().length === 0) {
    return new CSVResult([], [], []);
  }

  // Split into lines
  const lines = input.split(lineSeparator);
  const errors: CSVError[] = [];
  const parsedRows: Array<Record<string, any>> = [];

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse header row
  let headers: string[] = [];
  try {
    headers = parseRow(lines[0], delimiter, quoteChar);
  } catch (error) {
    errors.push({
      row: 1,
      message: `Failed to parse header row: ${error instanceof Error ? error.message : String(error)}`,
    });
    return new CSVResult([], [], errors);
  }

  // Parse data rows
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim().length === 0) {
      continue;
    }

    try {
      const fields = parseRow(line, delimiter, quoteChar);

      // Validate row length
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Row has ${fields.length} fields but expected ${headers.length}`,
        });
        continue;
      }

      // Build row object with type coercion
      const row: Record<string, any> = {};
      for (let j = 0; j < headers.length; j++) {
        row[headers[j]] = coerceValue(fields[j]);
      }

      parsedRows.push(row);
    } catch (error) {
      errors.push({
        row: i + 1,
        message: `Failed to parse row: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  return new CSVResult(parsedRows, headers, errors);
}

// ============================================================================
// Row Parser
// ============================================================================

/**
 * Parse a single CSV row, handling quoted fields and escaped quotes
 */
function parseRow(
  line: string,
  delimiter: string,
  quoteChar: string
): string[] {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = i + 1 < line.length ? line[i + 1] : '';

    // Handle quote character
    if (char === quoteChar) {
      if (inQuotes && nextChar === quoteChar) {
        // Escaped quote (two quotes = one literal)
        current += quoteChar;
        i += 2;
        continue;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
        continue;
      }
    }

    // Handle delimiter
    if (char === delimiter && !inQuotes) {
      fields.push(current);
      current = '';
      i++;
      continue;
    }

    // Regular character
    current += char;
    i++;
  }

  // Add last field
  fields.push(current);

  // Validate quote state
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

// ============================================================================
// Export Default
// ============================================================================

export default parseCSV;

