### GroupBy Operations

```typescript
const csv = `department,employee,salary
Sales,John,50000
Sales,Jane,55000
Engineering,Bob,80000
Engineering,Alice,85000
HR,Charlie,60000`;

const result = parseCSV(csv);

// Group by department
const byDept = result.groupBy('department');

Object.entries(byDept).forEach(([dept, employees]) => {
  const count = employees.length;
  const avgSalary = employees.reduce((sum, emp) => sum + emp.salary, 0) / count;

  console.log(`${dept}: ${count} employees, avg salary: $${avgSalary.toFixed(2)}`);
});

// Get specific group
const salesTeam = byDept['Sales'];
console.log(`Sales team members:`, salesTeam.map(e => e.employee));

// Further analysis
const engineeringAvg = byDept['Engineering']
  .reduce((sum, emp) => sum + emp.salary, 0) / byDept['Engineering'].length;
console.log(`Engineering avg: $${engineeringAvg.toFixed(2)}`);
```

### Combined Aggregations

```typescript
// Group, then analyze
const grouped = result.groupBy('department');

const stats = Object.entries(grouped).map(([dept, employees]) => ({
  department: dept,
  count: employees.length,
  avgSalary: employees.reduce((s, e) => s + e.salary, 0) / employees.length,
  maxSalary: Math.max(...employees.map(e => e.salary)),
  minSalary: Math.min(...employees.map(e => e.salary))
}));

console.table(stats);
