## Real-World Scenarios

### Sales Report Analysis

```typescript
const csv = `date,region,product,quantity,unit_price,status
2024-01-15,North,Widget A,100,29.99,Completed
2024-01-15,South,Widget B,50,39.99,Completed
2024-01-16,East,Widget A,75,29.99,Pending
2024-01-16,West,Widget C,200,19.99,Completed
2024-01-17,North,Widget B,25,39.99,Cancelled
2024-01-17,South,Widget A,150,29.99,Completed`;

const result = parseCSV(csv);

// Only completed orders
const completed = result.filter(row => row.status === 'Completed');

// Revenue by region
const byRegion = completed.groupBy('region');
Object.entries(byRegion).forEach(([region, orders]) => {
  const revenue = orders.reduce((sum, order) => 
    sum + (order.quantity * order.unit_price), 0
  );
  console.log(`${region}: $${revenue.toFixed(2)}`);
});

// Top selling product
const byProduct = completed.groupBy('product');
let topProduct = '';
let topRevenue = 0;

Object.entries(byProduct).forEach(([product, orders]) => {
  const revenue = orders.reduce((sum, order) => 
    sum + (order.quantity * order.unit_price), 0
  );
  if (revenue > topRevenue) {
    topRevenue = revenue;
    topProduct = product;
  }
});

console.log(`Top product: ${topProduct} ($${topRevenue.toFixed(2)})`);
```

