### Inventory Management

```typescript
const csv = `sku,product,quantity,min_stock,max_stock,unit_cost,last_updated
SKU001,Widget A,45,20,100,15.00,2024-01-15
SKU002,Widget B,5,10,50,25.00,2024-01-16
SKU003,Widget C,120,30,150,12.00,2024-01-15
SKU004,Gadget X,18,15,80,45.00,2024-01-14
SKU005,Gadget Y,0,5,40,55.00,2024-01-13`;

const result = parseCSV(csv);

// Items below minimum stock
const lowStock = result.filter(row => row.quantity < row.min_stock);
console.log('Items to reorder:');
lowStock.rows.forEach(row => {
  const needed = row.min_stock - row.quantity;
  const cost = needed * row.unit_cost;
  console.log(`  ${row.product}: need ${needed} units ($${cost.toFixed(2)})`);
});

// Total inventory value
const totalValue = result.rows.reduce((sum, row) => 
  sum + (row.quantity * row.unit_cost), 0
);
console.log(`Total inventory value: $${totalValue.toFixed(2)}`);

// Items near capacity
const nearMax = result.filter(row => row.quantity > row.max_stock * 0.8);
console.log(`\nItems near max capacity: ${nearMax.count()}`);

// Stock status summary
const status = {
  optimal: result.filter(row => 
    row.quantity >= row.min_stock && row.quantity <= row.max_stock
  ).count(),
  low: result.filter(row => row.quantity < row.min_stock).count(),
  high: result.filter(row => row.quantity > row.max_stock).count()
};

console.log(`\nInventory Status:`, status);
```

